import{_ as l}from"./nyalra_kb-7135827b.js";import{_ as p}from"./nyalra_no_mono-8344e451.js";import{_ as s,W as c,X as _,Y as i,Z as e,$ as t,a0 as o,a2 as m,a1 as d,C as a}from"./framework-a4c02b8f.js";const u={},f=e("figure",null,[e("img",{src:l,alt:"",tabindex:"0",loading:"lazy"}),e("figcaption")],-1),h={href:"https://tree-novel.com/works/episode/6370f15d86c3aa4965d60b3b1a149839.html",target:"_blank",rel:"noopener noreferrer"},k=e("p",null,"这是在互联网中栖息的不可思议生物·Nyalra于深夜写下的有关互联网、独居生活以及除此之外的事物的图文随笔。",-1),b=d('<hr><p>这个专栏连载已经刚好满一周年了，所以在这一期就做一个合适的收尾。话虽如此，除此之外我个人每天也都在投稿日记（译者注：见 @UZNp），而且讲谈社计划在二月发行我的小说（译者注：『蜘蛛』）。由于小说和这个专栏的编辑是同一个人，所以从我的角度来看，并没有什么离别的感觉。可以说是一个圆满的结局。</p><p>最后，似乎没有特别的用于结束的话题。无可奈何，那么在结束的时候夸一下自己吧，这个专栏一年来从未断更过。真厉害！尽管有时候在最后一刻提交，但总体来说，还是按时完成了。有过状态好的时候，甚至有过储备了大约六期专栏的时期。所以，完成的内容在一个月以上后才被公开，有时候会发现自己会想：「我写过这种东西吗？」「当时是这样写的，但现在完全不是那种心情了」，这种情况经常发生。人的情感和思考不会轻而易举地一直持续到一个月后。</p><p>这个专栏的主题是「面壁自语」，因此在 50 多次的连载中几乎没有其他人物登场。基本上是我一个人在脑海中打转，写下一些无关紧要的想法，以及不值得在我的社交媒体账号上写的小事。我自己挺喜欢这样的构成的，觉得挺有趣，但不可否认它是很小众的。反过来说，原本不是我正常读者的人，可能通过某种途径偶然找到这里，觉得不知道是什么但还是决定读一读的可能性还是相当大的。在网络的意外之处放置着意外的事物，这种经历对我来说是一种享受，所以如果这个专栏对某个人成为了稍微愉快的消遣，我会感到非常高兴。</p><p>在这种情况下，通常的最终回可能会有一些对结束的感想和感激，但正如前面所述，由于我的环境并没有发生太大变化，所以我并没有太多要思考的事情。毕竟这只是在对着墙壁说话，这种比较冷淡的态度也是符合主旨的。读者基本上都是对我的个人随笔发表回复，因此很少有人明确提到这个专栏的文章。并不是说我不感激，但也不至于大声说「谢谢！！！」。未来，只要我不疯狂地把一切搞得乱七八糟，我和现在的编辑将会继续在小说等方面进行合作，所以进行这个连载是有意义的。虽然路走得相当曲折，但也收获了一些东西，这样的曲折反而是一种好事。</p><p>……但是，这也只是我的个人故事，与读者无关。如果强行联系的话，可能是「小说那边也请多多关照！」的感觉。如果可以在这里放上链接或书影就好了，但不幸的是，因为小说计划在 2 月发行，所以两者都还没有公开。这算是一个相当微妙的结尾，但人生很长，网络上漂浮着无数的残骸，所以即使有这样微妙的结束也没关系。</p><p>那么，希望我们能在某个意外的地方，或是书店、Steam 等地再次相遇。再见了。感谢一年来的陪伴。</p><hr><p><img src="'+p+'" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/923807181345c6063c4795c91b306a5b.jpg" alt="" loading="lazy"></p><blockquote><p>本周的にゃるら的物品：</p><p>【にゃるら与房间的墙】一直以来，我都是坐在这个球形椅子上，对着墙壁说话。最近墙上装饰了 Turn A 和 Turn X，感觉也不那么寂寞了呢。因为这个专栏结束了，所以看不见的破壁对象又减少了。哭哭。</p></blockquote><p>晚安。</p>',11);function g(x,y){const n=a("ExternalLinkIcon"),r=a("RouterLink");return c(),_("div",null,[i(" more "),f,e("p",null,[t("原文链接："),e("a",h,[t("最終回／壁打ち最終回"),o(n)])]),e("blockquote",null,[k,e("p",null,[o(r,{to:"/posts/Translate/nyalra_kb_53.html"},{default:m(()=>[t("【奈亚拉面壁自语】第53回｜前提的共有【231121】")]),_:1})])]),b])}const C=s(u,[["render",g],["__file","nyalra_kb_54.html.vue"]]);export{C as default};
